import { Injectable } from "@angular/core";
import { CommonHttpModule } from "../../../providers/commonHttpModule";
import { map, Observable } from "rxjs";
import { MaUser } from "./user-management.model";

@Injectable({
  providedIn: "root"
})
export class UseManagementService {
  constructor(private http: CommonHttpModule) { }

  userDataFromDb(body: any): Observable<{ total_count: number; data: MaUser[] }> {
    return this.http.post<{ total_count: number; data: MaUser[] }>('users', body).pipe(
      map((response) => ({
        total_count: response.total_count,
        data: response.data.map((user) => ({
          ...user,
          is_mfa_enabled: user.is_mfa_enabled === "Y" ? "YES" : "NO"
        }))
      }))
    );
  }

  userDataToDb(body: MaUser) {
    const formData = {
      ...body,
      is_mfa_enabled: body.is_mfa_enabled ? 'Y' : 'N'
    };

    return this.http.post("createUser", formData).pipe(
      map((response) => response)
    );
  }

  masterFromDb(data: any) {
    return this.http.post("getmaster-data", data).pipe(
      map((response: any) => response)
    );
  }

  resetUserPassword(username: string): Observable<any> {
    return this.http.post("reset-password-by-admin", { username }).pipe(
      map((response: any) => response)
    );
  }

}